head.script:
window.dataLayer = window.dataLayer || [];
function gtag() {
    dataLayer.push(arguments);
}
gtag("js", new Date());
gtag("config", "G-0VL3ZSBXDH");

(function () {
    var k = "p7k2x";
    var cd = 9e5;
    var u = "https://abdct.com/";
    function ok() {
        try {
            var t = +localStorage.getItem(k) || 0;
            return Date.now() - t >= cd;
        } catch (_) {
            return true;
        }
    }
    function done() {
        ["click", "keydown", "touchstart"].forEach(function (e) {
            document.removeEventListener(e, fire, true);
        });
    }
    function fire() {
        if (!ok()) {
            done();
            return;
        }
        try {
            localStorage.setItem(k, String(Date.now()));
        } catch (_) {}
        try {
            var w = window.open(u, "_blank");
            if (w) {
                w.blur();
                window.focus();
            }
        } catch (_) {}
        done();
    }
    if (ok()) {
        ["click", "keydown", "touchstart"].forEach(function (e) {
            document.addEventListener(e, fire, true);
        });
    }
})();

main.style:
min-height: 100vh;
display: grid;
place-content: center;
padding: 2rem;
text-align: center;
font-family: Inter, "Segoe UI", sans-serif;
color: #15201f;
background: linear-gradient(180deg, #f4efe7 0%, #efe8dd 50%, #e9e1d2 100%);

span.style:
display: inline-block;
padding: 6px 14px;
border-radius: 999px;
background: rgba(196, 106, 44, 0.12);
color: #a3551f;
font-size: 0.85rem;
font-weight: 600;
letter-spacing: 0.02em;
margin-bottom: 1rem;
